import React, { useState } from "react";
import FloatingInput from "../component/FloatingInput";

export default function AdminCreateUser({ closeModal }) {
  const [user, setUser] = useState({
    username: "",
    name: "",
    email: "",
    password: "",
    role: "Student",
  });

  const [errors, setErrors] = useState({});
  const [success, setSuccess] = useState("");

  const BASE_URL = "http://localhost:8086";

  const handleChange = (e) => {
    setUser({ ...user, [e.target.name]: e.target.value });
    setErrors({ ...errors, [e.target.name]: "" });
  };

  const validate = () => {
    const err = {};

    if (!user.username) err.username = "Username is required";
    if (!user.name) err.name = "Full name is required";

    if (!user.email) {
      err.email = "Email is required";
    } else if (user.role === "Student") {
      if (!/^[iI][tT]\d{8}@my\.sliit\.lk$/.test(user.email)) {
        err.email = "Use ITXXXXXXXX@my.sliit.lk format";
      }
    }

    if (!user.password) {
      err.password = "Password is required";
    } else if (user.password.length < 6) {
      err.password = "Minimum 6 characters required";
    }

    return err;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const validationErrors = validate();
    if (Object.keys(validationErrors).length > 0) {
      setErrors(validationErrors);
      return;
    }

    try {
      const res = await fetch(`${BASE_URL}/user/admin/create`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(user),
      });

      if (res.ok) {
        setSuccess("User created successfully 🎉");

        setUser({
          username: "",
          name: "",
          email: "",
          password: "",
          role: "Student",
        });

        setTimeout(() => closeModal(), 1200);
      } else {
        setErrors({ submit: "Failed to create user" });
      }
    } catch {
      setErrors({ submit: "Server not responding" });
    }
  };

  return (
    <div className="fixed inset-0 z-50">
      {/* BACKDROP */}
      <div
        className="absolute inset-0 bg-black/40 backdrop-blur-sm"
        onClick={closeModal}
      />

      {/* CENTER WRAPPER */}
      <div className="absolute inset-0 flex items-center justify-center">
        <div className="w-[500px] p-8 rounded-2xl 
          bg-white/20 backdrop-blur-xl border border-white/30 
          shadow-2xl transform-gpu">

          <h2 className="text-2xl font-bold text-white text-center mb-6">
            Admin Create User
          </h2>

          {success && <p className="text-green-300 text-center mb-3">{success}</p>}
          {errors.submit && <p className="text-red-300 text-center mb-3">{errors.submit}</p>}

          <form onSubmit={handleSubmit} className="space-y-4">

            <FloatingInput name="username" label="Username" value={user.username} onChange={handleChange} />
            <FloatingInput name="name" label="Full Name" value={user.name} onChange={handleChange} />
            <FloatingInput name="email" type="email" label="Email" value={user.email} onChange={handleChange} />
            <FloatingInput name="password" type="password" label="Password" value={user.password} onChange={handleChange} />

            <select
              name="role"
              value={user.role}
              onChange={handleChange}
              className="w-full px-4 py-3 rounded-lg bg-white/10 border border-white/30 text-white"
            >
              <option value="Student">Student</option>
              <option value="Admin">Admin</option>
              <option value="Academic Panel">Academic Panel</option>
            </select>

            <button className="w-full py-2 rounded-lg bg-white/30 hover:bg-white/40 text-white">
              Create User
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}
